-- PDB에서 수동 ADDM 분석 수행
DECLARE
  v_task_name  VARCHAR2(100) := 'PDB_ADDM_MANUAL_' || TO_CHAR(SYSDATE, 'YYYYMMDD_HH24MISS');
  v_task_desc  VARCHAR2(200) := 'PDB 레벨 수동 ADDM 분석';
  v_begin_snap NUMBER;
  v_end_snap   NUMBER;
BEGIN
  -- 최근 2개 스냅샷 ID 조회
  SELECT MAX(snap_id) INTO v_end_snap
  FROM   DBA_HIST_SNAPSHOT
  WHERE  con_id = SYS_CONTEXT('USERENV', 'CON_ID');

  SELECT MAX(snap_id) INTO v_begin_snap
  FROM   DBA_HIST_SNAPSHOT
  WHERE  snap_id < v_end_snap
    AND  con_id = SYS_CONTEXT('USERENV', 'CON_ID');

  -- ADDM 태스크 생성 및 실행
  DBMS_ADDM.ANALYZE_DB(
    task_name    => v_task_name,
    begin_snap   => v_begin_snap,
    end_snap     => v_end_snap,
    db_id        => NULL    -- 현재 DB
  );

  DBMS_OUTPUT.PUT_LINE('ADDM Task: ' || v_task_name);
  DBMS_OUTPUT.PUT_LINE('Snap Range: ' || v_begin_snap || ' ~ ' || v_end_snap);
END;
/

-- PDB ADDM 결과 보고서 출력
SELECT DBMS_ADVISOR.GET_TASK_REPORT(
         task_name => (SELECT MAX(task_name)
                       FROM DBA_ADVISOR_TASKS
                       WHERE advisor_name = 'ADDM'
                         AND status = 'COMPLETED'),
         type      => 'TEXT'
       ) AS addm_report
FROM   DUAL;

-- 수동 ADDM 태스크 생성 및 실행 (DBMS_ADVISOR 사용)
DECLARE
  v_task_name  VARCHAR2(100) := 'MY_ADDM_ANALYSIS';
  v_task_id    NUMBER;
BEGIN
  -- 1. ADDM 태스크 생성
  DBMS_ADVISOR.CREATE_TASK(
    advisor_name  => 'ADDM',
    task_name     => v_task_name,
    task_desc     => '특정 기간 수동 ADDM 분석'
  );

  -- 2. 분석할 스냅샷 범위 설정
  DBMS_ADVISOR.SET_TASK_PARAMETER(
    task_name  => v_task_name,
    parameter  => 'START_SNAPSHOT',
    value      => 100   -- 시작 스냅샷 ID
  );
  DBMS_ADVISOR.SET_TASK_PARAMETER(
    task_name  => v_task_name,
    parameter  => 'END_SNAPSHOT',
    value      => 110   -- 종료 스냅샷 ID
  );

  -- 3. (선택) DB Time 임계값 조정
  DBMS_ADVISOR.SET_TASK_PARAMETER(
    task_name  => v_task_name,
    parameter  => 'DBTIME_THRESHOLD',
    value      => 0.5   -- 0.5% 이상의 문제만 보고
  );

  -- 4. 태스크 실행
  DBMS_ADVISOR.EXECUTE_TASK(v_task_name);

  DBMS_OUTPUT.PUT_LINE('ADDM 분석 완료: ' || v_task_name);
END;
/

-- 5. 결과 보고서 조회
SELECT DBMS_ADVISOR.GET_TASK_REPORT('MY_ADDM_ANALYSIS', 'TEXT') AS report
FROM   DUAL;

-- DBMS_ADDM.ANALYZE_DB를 이용한 간편한 전체 DB 분석
VARIABLE v_task VARCHAR2(100);
BEGIN
  :v_task := 'QUICK_ADDM_' || TO_CHAR(SYSDATE, 'YYYYMMDD_HH24MISS');
  DBMS_ADDM.ANALYZE_DB(
    task_name    => :v_task,
    begin_snap   => 100,
    end_snap     => 120
  );
END;
/

-- 결과 조회
SELECT DBMS_ADVISOR.GET_TASK_REPORT(:v_task, 'TEXT') AS report
FROM   DUAL;

