-- 두 스냅샷 사이의 ADDM 분석
DECLARE
  v_task_name VARCHAR2(100) := 'IMMEDIATE_ADDM';
  v_begin_snap NUMBER;
  v_end_snap   NUMBER;
BEGIN
  -- 최근 2개 스냅샷 조회
  SELECT snap_id INTO v_end_snap
  FROM   (SELECT snap_id FROM DBA_HIST_SNAPSHOT
          ORDER BY snap_id DESC)
  WHERE  ROWNUM = 1;

  SELECT snap_id INTO v_begin_snap
  FROM   (SELECT snap_id FROM DBA_HIST_SNAPSHOT
          WHERE snap_id < v_end_snap
          ORDER BY snap_id DESC)
  WHERE  ROWNUM = 1;

  DBMS_ADDM.ANALYZE_DB(
    task_name  => v_task_name,
    begin_snap => v_begin_snap,
    end_snap   => v_end_snap
  );

  DBMS_OUTPUT.PUT_LINE('분석 완료: ' || v_begin_snap || ' ~ ' || v_end_snap);
END;
/

-- 결과 확인
SELECT DBMS_ADVISOR.GET_TASK_REPORT('IMMEDIATE_ADDM', 'TEXT') AS report
FROM   DUAL;
